+export fn PyState_RemoveModule(def: *PyModuleDef) callconv(.c) c_int {
+    if (def.m_base.m_index <= 0) return -1;
+
+    const idx: usize = @intCast(def.m_base.m_index);
+    if (idx >= module_registry.len) return -1;
+
+    if (module_registry[idx]) |mod| {
+        traits.decref(mod);
