+    const seq: *PyStructSequence = @ptrCast(@alignCast(memory.ptr));
+    seq.ob_base.ob_base.ob_refcnt = 1;
+    seq.ob_base.ob_base.ob_type = type_obj;
+    seq.ob_base.ob_size = @intCast(n_items);
