+    if (pos < 0 or pos >= ss.ob_base.ob_size) return;
+
+    const idx: usize = @intCast(pos);
+    if (ss.ob_item[idx]) |old| {
+        traits.decref(old);
+    }
+    ss.ob_item[idx] = obj;
