+/// PyDict_Pop - Remove key and return value (or default if not found)
+export fn PyDict_Pop(obj: *cpython.PyObject, key: *cpython.PyObject, default_value: ?*cpython.PyObject) callconv(.c) ?*cpython.PyObject {
