+    const min_long: i64 = std.math.minInt(c_long);
+
+    if (val > max_long) {
+        overflow.* = 1;
+        return -1;
+    }
+    if (val < min_long) {
+        overflow.* = -1;
+        return -1;
+    }
+
+    overflow.* = 0;
+    return @intCast(val);
