+/// Get truth value of object
+pub fn toBool(obj: *cpython.PyObject) bool {
+    const type_obj = cpython.Py_TYPE(obj);
+
+    // Use nb_bool if available
+    if (type_obj.tp_as_number) |num| {
+        if (num.nb_bool) |bool_fn| {
