+    const type_obj = cpython.Py_TYPE(obj);
+    if (type_obj.tp_as_number) |num| {
+        if (num.nb_int) |int_fn| {
+            const result = int_fn(obj) orelse return null;
+            defer decref(result);
+            return pylong.PyLong_AsLong(result);
+        }
+    }
+
+    return null;
